using System.Diagnostics;
using TextAnalysis;

const int WarmupIterations = 50;
const int MeasuredIterations = 1000;
const int OpsPerIteration = 500;

var sampleText = string.Join(" ",
    Enumerable.Range(0, 1000).Select(i => i switch
    {
        _ when i % 7 == 0 => "extraordinary",
        _ when i % 5 == 0 => "the",
        _ when i % 3 == 0 => "benchmark",
        _ when i % 2 == 0 => "performance",
        _ => "test"
    }));

var analyzer = new TextAnalyzer(sampleText);

// Verify correctness
Console.WriteLine($"Runtime: {Environment.Version}");
Console.WriteLine($"WordCount: {analyzer.WordCount}");
Console.WriteLine($"AverageWordLength: {analyzer.AverageWordLength():F4}");
Console.WriteLine($"WordLengthHistogram length: {analyzer.WordLengthHistogram().Count}");
Console.WriteLine($"UniqueWordCount: {analyzer.UniqueWordCount()}");
Console.WriteLine();

Benchmark("AverageWordLength", () => analyzer.AverageWordLength());
Benchmark("WordLengthHistogram", () => analyzer.WordLengthHistogram());
Benchmark("UniqueWordCount", () => analyzer.UniqueWordCount());

void Benchmark(string name, Action action)
{
    // Warmup
    for (int i = 0; i < WarmupIterations; i++)
        for (int j = 0; j < OpsPerIteration; j++)
            action();

    // Measure
    var timings = new double[MeasuredIterations];
    var sw = new Stopwatch();
    for (int i = 0; i < MeasuredIterations; i++)
    {
        sw.Restart();
        for (int j = 0; j < OpsPerIteration; j++)
            action();
        sw.Stop();
        timings[i] = sw.Elapsed.TotalNanoseconds / OpsPerIteration;
    }

    Array.Sort(timings);
    // Trim top/bottom 10% for robustness against noise
    int trimCount = MeasuredIterations / 10;
    var trimmed = timings.AsSpan(trimCount, MeasuredIterations - 2 * trimCount);
    double mean = 0;
    foreach (var t in trimmed) mean += t;
    mean /= trimmed.Length;
    double variance = 0;
    foreach (var t in trimmed) variance += (t - mean) * (t - mean);
    double stddev = Math.Sqrt(variance / trimmed.Length);

    double median = trimmed[trimmed.Length / 2];
    double p5 = trimmed[(int)(trimmed.Length * 0.05)];
    double p95 = trimmed[(int)(trimmed.Length * 0.95)];

    Console.WriteLine($"{name,-25} | Mean: {mean,10:F2} ns | StdDev: {stddev,8:F2} ns | Median: {median,10:F2} ns | P5: {p5,10:F2} ns | P95: {p95,10:F2} ns");
}

